#include <bits/stdc++.h>
using namespace std;

const int N=5e4+4;

struct Node{
    int s1,s2;
    Node *son[2];
}*root;

void clear(Node *p){
    p->son[0]=p->son[1]=NULL;
    p->s1=p->s2=0;
}

void dfs(Node *p){
    if(p->son[0]!=NULL)
        dfs(p->son[0]),p->s2+=p->son[0]->s2+p->son[0]->s1;
    if(p->son[1]!=NULL)
        dfs(p->son[1]),p->s2+=p->son[1]->s2+p->son[1]->s1;
}

int n,m;

int main(){
    root=new Node;
    clear(root);
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        int len,a;
        Node *p=root;
        scanf("%d",&len);
        while(len--){
            scanf("%d",&a);
            if(p->son[a]==NULL){
                Node *q=new Node;
                clear(q);
                p->son[a]=q;
            }
            p=p->son[a];
        }
        p->s1++;
    }
    dfs(root);
    for(int i=1;i<=m;i++){
        int len,a,sum=0;
        bool flag=true;
        Node *p=root;
        scanf("%d",&len);
        while(len--){
            scanf("%d",&a);
            if(p->son[a]==NULL)
                flag=false;
            if(flag)
            	p=p->son[a],sum+=p->s1;
        }
        if(flag)
        	sum+=p->s2;
        printf("%d\n",sum);
    }
    return 0;
}
